#' GLM Power Analysis
#'
#' General Linear Model. Estimates models using \code{lm()} function and 
#' provides options to facilitate estimation of 
#' interactions, simple slopes, simple effects, post-hoc tests, contrast 
#' analysis, effect size indexes and visualization of the results.
#' 
#'
#' @examples
#' \dontrun{
#' data('ToothGrowth')
#' gamlj::gamljGlm(formula = len ~ supp,  data = ToothGrowth)
#'}
#' @param data the data as a data frame
#' @param .caller .
#' @param .interface .
#' @param dep a string naming the dependent variable from \code{data}; the
#'   variable must be numeric. Not needed if \code{formula} is used.
#' @param factors a vector of strings naming the fixed factors from
#'   \code{data}. Not needed if \code{formula} is used.
#' @param covs a vector of strings naming the covariates from \code{data}. Not
#'   needed if \code{formula} is used.
#' @param model_terms a list of character vectors describing fixed effects
#'   terms. Not needed if \code{formula} is used.
#' @param alpha .
#' @param power .
#' @param n .
#' @param obtain .
#' @param r2_value .
#' @param r2_input .
#' @param mute Not present in R
#' @param model_type .
#' @param es
#' @param fixed_sizes .
#' @param donotrun .
#' @return A results object containing:
#' \tabular{llllll}{
#'   \code{results$model} \tab \tab \tab \tab \tab a property \cr
#'   \code{results$info} \tab \tab \tab \tab \tab a table \cr
#'   \code{results$recap} \tab \tab \tab \tab \tab a html \cr
#'   \code{results$r2} \tab \tab \tab \tab \tab a table \cr
#'   \code{results$anova} \tab \tab \tab \tab \tab a table of ANOVA results \cr
#'   \code{results$coefficients} \tab \tab \tab \tab \tab a table of coefficients results \cr
#' }
#'
#' Tables can be converted to data frames with \code{asDF} or \code{\link{as.data.frame}}. For example:
#'
#' \code{results$info$asDF}
#'
#' \code{as.data.frame(results$info)}
#'
#' @export
pamljlm <- function(
    data,
    .caller = "lm",
    .interface = "jamovi",
    dep = NULL,
    factors = NULL,
    covs = NULL,
    model_terms = NULL,
    alpha = 0.05,
    power = 0.8,
    n = 100,
    obtain = "n",
    r2_value = 0,
    r2_input = FALSE,
    mute = FALSE,
    model_type = "lm",
    es = "etap",
    fixed_sizes,
    donotrun = FALSE) {

    if ( ! requireNamespace("jmvcore", quietly=TRUE))
        stop("pamljlm requires jmvcore to be installed (restart may be required)")

    if ( ! missing(dep)) dep <- jmvcore::resolveQuo(jmvcore::enquo(dep))
    if ( ! missing(factors)) factors <- jmvcore::resolveQuo(jmvcore::enquo(factors))
    if ( ! missing(covs)) covs <- jmvcore::resolveQuo(jmvcore::enquo(covs))
    if (missing(data))
        data <- jmvcore::marshalData(
            parent.frame(),
            `if`( ! missing(dep), dep, NULL),
            `if`( ! missing(factors), factors, NULL),
            `if`( ! missing(covs), covs, NULL))

    for (v in factors) if (v %in% names(data)) data[[v]] <- as.factor(data[[v]])
    if (inherits(model_terms, "formula")) model_terms <- jmvcore::decomposeFormula(model_terms)

    options <- pamljlmOptions$new(
        .caller = .caller,
        .interface = .interface,
        dep = dep,
        factors = factors,
        covs = covs,
        model_terms = model_terms,
        alpha = alpha,
        power = power,
        n = n,
        obtain = obtain,
        r2_value = r2_value,
        r2_input = r2_input,
        mute = mute,
        model_type = model_type,
        es = es,
        fixed_sizes = fixed_sizes,
        donotrun = donotrun)

    analysis <- pamljlmClass$new(
        options = options,
        data = data)

    analysis$run()

    analysis$results
}

